import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"颐和园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/index.md","filePath":"landmarks/summer-palace/index.md","lastUpdated":1784720050000}'),n={name:"landmarks/summer-palace/index.md"};function d(i,t,s,g,o,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="颐和园" tabindex="-1">颐和园 <a class="header-anchor" href="#颐和园" aria-label="Permalink to &quot;颐和园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1573657860396-d7b1656adc53?w=1200&amp;q=80" alt="颐和园昆明湖"></p><blockquote><p>&quot;虽由人作，宛自天开。&quot; —— 中国造园艺术的最高境界，颐和园正是其巅峰之作</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>颐和园位于北京西郊，是以昆明湖、万寿山为基址，以杭州西湖为蓝本，汲取江南园林精华而建的大型山水园林，也是中国现存规模最大、保存最完整的皇家行宫御苑，被誉为&quot;皇家园林博物馆&quot;。全园占地约290公顷，其中昆明湖约占四分之三，万寿山雄踞湖北，殿宇楼阁依山就势，湖光山色浑然一体。</p><p>颐和园始建于清乾隆十五年（1750年），是乾隆为母亲崇庆皇太后祝寿而建的&quot;清漪园&quot;，工程历时十五年，耗银480万两，为&quot;三山五园&quot;中最后建成的一座。咸丰十年（1860年），清漪园遭英法联军焚掠，珍宝荡然无存。光绪十二年（1886年），慈禧太后挪用海军军费重建，取&quot;颐养冲和&quot;之意改名&quot;颐和园&quot;，作为其夏季避暑听政之所。1900年园内建筑再遭八国联军破坏，两年后修复。1924年颐和园正式对公众开放，1961年列为全国重点文物保护单位，1998年被联合国教科文组织列入《世界遗产名录》。</p><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">1750年（乾隆十五年）</td><td style="text-align:left;">始建清漪园，耗银480万两，历时十五年建成</td></tr><tr><td style="text-align:left;">1860年（咸丰十年）</td><td style="text-align:left;">英法联军焚掠，园内珍宝荡然无存</td></tr><tr><td style="text-align:left;">1886年（光绪十二年）</td><td style="text-align:left;">慈禧挪用海军军费重建，1888年改名&quot;颐和园&quot;</td></tr><tr><td style="text-align:left;">1900年（光绪二十六年）</td><td style="text-align:left;">八国联军再遭破坏，1902年修复</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">正式对公众开放</td></tr><tr><td style="text-align:left;">1998年</td><td style="text-align:left;">列入联合国教科文组织《世界遗产名录》</td></tr></tbody></table><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00（旺季），6:30-19:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>园中园</strong></td><td style="text-align:left;">8:00-17:30（旺季），8:30-17:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票30元，联票60元（含德和园、佛香阁、苏州街、文昌院）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">4-6小时（半天至一天）</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，春秋最佳，夏季荷花最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线北宫门站（北宫门）、西苑站（东宫门）</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">颐和园官网或微信公众号预约，旺季建议提前</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">看点</th><th style="text-align:center;">建议时长</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/renshou-dian.html">仁寿殿</a></td><td style="text-align:left;">慈禧听政之所，殿前铜凤压铜龙</td><td style="text-align:center;">30分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a></td><td style="text-align:left;">清代三大戏楼之一，慈禧看戏处</td><td style="text-align:center;">40分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a></td><td style="text-align:left;">慈禧万寿庆典场所，前山中轴核心</td><td style="text-align:center;">30分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a></td><td style="text-align:left;">全园标志，俯瞰昆明湖全景</td><td style="text-align:center;">1小时</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a></td><td style="text-align:left;">世界第一长廊，万幅苏式彩画</td><td style="text-align:center;">40分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">昆明湖与十七孔桥</a></td><td style="text-align:left;">冬至&quot;金光穿洞&quot;奇观，铜牛镇水</td><td style="text-align:center;">1-2小时</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫（清晏舫）</a></td><td style="text-align:left;">巨石雕成的不沉之舟</td><td style="text-align:center;">30分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/suzhou-street.html">苏州街</a></td><td style="text-align:left;">后湖两岸的江南水街，皇家&quot;买卖街&quot;</td><td style="text-align:center;">40分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/xiequ-yuan.html">谐趣园</a></td><td style="text-align:left;">仿寄畅园的&quot;园中之园&quot;</td><td style="text-align:center;">40分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤六桥</a></td><td style="text-align:left;">仿西湖苏堤，玉带桥最负盛名</td><td style="text-align:center;">1小时</td></tr></tbody></table><h2 id="推荐游览路线" tabindex="-1">推荐游览路线 <a class="header-anchor" href="#推荐游览路线" aria-label="Permalink to &quot;推荐游览路线&quot;">​</a></h2><h3 id="北宫门线-4-5小时-山水之选" tabindex="-1">北宫门线（4-5小时，山水之选） <a class="header-anchor" href="#北宫门线-4-5小时-山水之选" aria-label="Permalink to &quot;北宫门线（4-5小时，山水之选）&quot;">​</a></h3><p>北宫门进 → <a href="/beijing-travel-guide/landmarks/summer-palace/suzhou-street.html">苏州街</a> → 须弥灵境 → <a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫</a> → 乘船至南湖岛 → <a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">十七孔桥</a> → 铜牛 → 东宫门或新建宫门出</p><p><strong>适合人群</strong>：初次到访、体力较好者。由山至水，一路下行，尽览前山精华。</p><h3 id="东宫门线-4-5小时-人文之选" tabindex="-1">东宫门线（4-5小时，人文之选） <a class="header-anchor" href="#东宫门线-4-5小时-人文之选" aria-label="Permalink to &quot;东宫门线（4-5小时，人文之选）&quot;">​</a></h3><p>东宫门进 → <a href="/beijing-travel-guide/landmarks/summer-palace/renshou-dian.html">仁寿殿</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a> → 玉澜堂 → 乐寿堂 → <a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a> → <a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫</a> → 沿<a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤</a>漫步 → 新建宫门出</p><p><strong>适合人群</strong>：喜欢历史人文、想细看宫廷旧迹者。先殿宇后山水，节奏从容。</p><h2 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">景色</th><th style="text-align:left;">最佳时间</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>春</strong></td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤</a>桃红柳绿，山桃映水</td><td style="text-align:left;">3月中旬-4月中旬</td></tr><tr><td style="text-align:left;"><strong>夏</strong></td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">昆明湖</a>荷花盛放，画舫凌波</td><td style="text-align:left;">7月-8月</td></tr><tr><td style="text-align:left;"><strong>秋</strong></td><td style="text-align:left;">桂香满园，菊花展、银杏红叶层林尽染</td><td style="text-align:left;">10月下旬-11月</td></tr><tr><td style="text-align:left;"><strong>冬</strong></td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">十七孔桥</a>&quot;金光穿洞&quot;，西山晴雪</td><td style="text-align:left;">冬至前后、雪后初晴</td></tr></tbody></table><h2 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h2><ol><li><strong>联票更划算</strong>：联票已含佛香阁、德和园、苏州街、文昌院，单买这些园中园反而更贵，时间充裕建议直接买联票。</li><li><strong>早到避人流</strong>：旺季开园即入，先直奔佛香阁或长廊，避开上午10点后的大客流。</li><li><strong>善用游船</strong>：石舫至南湖岛的游船（大船40元）既省力又是移动观景台，可从湖上回望佛香阁全景。</li><li><strong>穿舒适鞋</strong>：万寿山台阶陡峭，环湖一圈十余公里，一双好鞋比什么都重要。</li><li><strong>预留拍照时间</strong>：佛香阁俯瞰（南湖岛）、十七孔桥夕阳（东堤）、长廊光影，都是出片圣地，日落前1小时光线最佳。</li><li><strong>周边联游</strong>：可与<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园</a>安排在同一天，两园相距仅数公里，感受&quot;毁灭与重生&quot;的历史对照。</li></ol><hr><p><strong>📍 地址</strong>：北京市海淀区新建宫门路19号 <strong>📞 电话</strong>：010-62881144 <strong>🌐 官网</strong>：<a href="http://www.summerpalace-china.com" target="_blank" rel="noreferrer">www.summerpalace-china.com</a></p>',24)])])}const f=e(n,[["render",d]]);export{u as __pageData,f as default};
